#include <iostream>
#include <string>
#include <vector>
#include <sstream>

int main() {
    std::string line;
    std::getline(std::cin, line);
    int base = std::stoi(line);

    std::getline(std::cin, line);
    int exponent = std::stoi(line);

    long long result = 1;
    if (exponent < 0) {
        std::cout << "Exponent must be a positive integer." << std::endl;
        return 1;
    }
    for (int i = 0; i < exponent; ++i) {
        result *= base;
    }
    std::cout << result << std::endl;
    return 0;
}
